pr_description:
Fixture for https://github.com/lint-staged/lint-staged/issues/1398

**By proposed changes user will get the opportunity to control/handle the execution of custom task, As you can see in following example `.lintstagedrc.js`.** 

```
async function doFoo(files) {
  const { execa } = await import("execa");
  const result = await execa("eslint", [...files],
  {
    preferLocal: true,
    reject: false,
    shell: false,
    stdin: 'ignore'
  });
  if (result.failed || result.killed || result.signal != null) {
    throw result
  }
}

module.exports = {
  "**/*.{js,jsx}": {
      title: "Running a custom task",
      task: async (filenames) =>  {
        console.time()
        await doFoo(filenames)
        console.timeEnd()
      }
  },
};
```

**Following will be the output in case of no-console eslint error**

![image](https://github.com/lint-staged/lint-staged/assets/11659536/7e41fa40-1bf8-4f90-9064-41ce4bee3b55)

diff_text:
diff --git a/test/unit/validateConfig.spec.js b/test/unit/validateConfig.spec.js
index 49178aa..1ec6d46 100644
--- a/test/unit/validateConfig.spec.js
+++ b/test/unit/validateConfig.spec.js
@@ -25,6 +25,30 @@ describe('validateConfig', () => {
     expect(() => validateConfig(invalidConfig, configPath, logger)).toThrowErrorMatchingSnapshot()
   })

+  it('should throw and should print validation errors for invalid object config', () => {
+    const invalidConfig = {
+      '*.js': {
+        title: 'Running a custom task',
+      },
+    }
+
+    expect(() => validateConfig(invalidConfig, configPath, logger)).toThrowErrorMatchingSnapshot()
+  })
+
+  it('should not throw and should print nothing for valid object config', () => {
+    const validObjectConfig = {
+      '*.js': {
+        title: 'Running a custom task',
+        task: async (files) => {
+          console.log(files)
+        },
+      },
+    }
+
+    expect(() => validateConfig(validObjectConfig, configPath, logger)).not.toThrow()
+    expect(logger.printHistory()).toEqual('')
+  })
+
   it('should throw for empty config', () => {
     expect(() => validateConfig({}, configPath, logger)).toThrowErrorMatchingSnapshot()
   })

